def inorderTraversal(self, root: TreeNode) -> List[int]: """
    Traverse the binary tree in-order and return a list of node values.
    """
    result = []
    stack = [root]
    while stack:
        node = stack.pop()
        if node:
            stack.append(node.right)
            stack.append(node)
            stack.append(node.left)
    return result

class Solution:
    def inorderTraversal(self, root: TreeNode) -> List[int]:
        return inorderTraversal(root)

