#include <vector>

class Solution {
public:
    vector<int> inorderTraversal(TreeNode* root) {
        vector<int> result;
        stack<TreeNode*> st;
        while (!st.empty() || root) {
            if (root) {
                st.push(root);
                root = root->left;
            } else {
                root = st.top();
                result.push_back(root->val);
                st.pop();
                root = root->right;
            }
        }
        return result;
    }
};
